const API_BASE_URL = process.env.NEXT_PUBLIC_API_BASE_URL || "https://localhost:8000";

export interface ApiError {
  status: number;
  message: string;
  details?: unknown;
}

export type HttpMethod = "GET" | "POST" | "PUT" | "PATCH" | "DELETE";

export interface RequestOptions<TBody = unknown> extends Omit<RequestInit, "body"> {
  /**
   * Query string parameters, will be appended to the URL.
   */
  params?: Record<string, string | number | boolean | undefined | null>;
  body?: TBody;
}

function buildUrl(path: string, params?: RequestOptions["params"]) {
  const url = new URL(path, API_BASE_URL || "http://localhost");
  if (params) {
    Object.entries(params).forEach(([key, value]) => {
      if (value === undefined || value === null) return;
      url.searchParams.append(key, String(value));
    });
  }
  if (!API_BASE_URL) {
    return `${path.startsWith("/") ? "" : "/"}${url.pathname}${url.search}`;
  }
  return url.toString();
}

async function handleResponse<T>(res: Response): Promise<T> {
  const contentType = res.headers.get("content-type") || "";
  const isJson = contentType.includes("application/json");
  const rawText = await res.text().catch(() => "");

  const parsed = (() => {
    if (!isJson) return rawText;
    try {
      return rawText ? JSON.parse(rawText) : null;
    } catch {
      return rawText;
    }
  })();

  if (!res.ok) {
    const message =
      (isJson &&
        parsed &&
        typeof parsed === "object" &&
        ("message" in parsed || "error" in parsed) &&
        ((parsed as { message?: string; error?: string }).message ||
          (parsed as { message?: string; error?: string }).error)) ||
      res.statusText ||
      "Request failed";
    const err: ApiError = {
      status: res.status,
      message,
      details: parsed ?? rawText,
    };
    throw err;
  }

  return (parsed as T) ?? (undefined as unknown as T);
}

function toBody(body: unknown): BodyInit | undefined {
  if (body === undefined || body === null) return undefined;
  if (body instanceof FormData || body instanceof Blob || body instanceof ArrayBuffer) {
    return body;
  }
  if (typeof body === "string") return body;
  return JSON.stringify(body);
}

export async function apiRequest<TResponse, TBody = unknown>(
  path: string,
  method: HttpMethod,
  options: RequestOptions<TBody> = {},
): Promise<TResponse> {
  const url = buildUrl(path, options.params);

  const headers = new Headers(options.headers);

  const preparedBody = toBody(options.body);
  if (preparedBody && !headers.has("Content-Type") && !(preparedBody instanceof FormData)) {
    headers.set("Content-Type", "application/json");
  }

  const res = await fetch(url, {
    ...options,
    method,
    headers,
    body: preparedBody,
  });

  return handleResponse<TResponse>(res);
}

export function apiGet<TResponse>(path: string, options?: RequestOptions) {
  return apiRequest<TResponse>(path, "GET", options);
}

export function apiPost<TResponse, TBody = unknown>(
  path: string,
  body?: TBody,
  options?: RequestOptions<TBody>,
) {
  return apiRequest<TResponse, TBody>(path, "POST", { ...options, body });
}

export function apiPut<TResponse, TBody = unknown>(
  path: string,
  body?: TBody,
  options?: RequestOptions<TBody>,
) {
  return apiRequest<TResponse, TBody>(path, "PUT", { ...options, body });
}

export function apiPatch<TResponse, TBody = unknown>(
  path: string,
  body?: TBody,
  options?: RequestOptions<TBody>,
) {
  return apiRequest<TResponse, TBody>(path, "PATCH", { ...options, body });
}

export function apiDelete<TResponse>(path: string, options?: RequestOptions) {
  return apiRequest<TResponse>(path, "DELETE", options);
}
