import { apiGet } from "@/lib/httpClient";

export interface ProductLegacyDetailDto {
  id: number;
  code: string;
  name: string;
  nameEn: string | null;
  content: string | null;
  contentEn: string | null;
  shortContent: string | null;
  shortContentEn: string | null;
  image: string | null;
  image2: string | null;
  image3: string | null;
  image4: string | null;
  price1: number;
  originalPrice: number | null;
  finalPrice: number;
  categoryId: number;
  categoryName: string;
  providerId: number | null;
  providerName: string | null;
  packed: string | null;
  pin: string | null;
  type: string | null;
  origin: string | null;
  unit: string | null;
  quantity: number;
  isNewProduct: boolean;
  isActive: boolean;
  dateAdded: string;
}

interface ApiEnvelope<T> {
  success: boolean;
  data: T;
  error: string | null;
  traceId: string | null;
}

const PRODUCT_LEGACY_URL = "/client/v1/products";

export async function getProductLegacy(productId: number): Promise<ProductLegacyDetailDto> {
  const envelope = await apiGet<ApiEnvelope<ProductLegacyDetailDto>>(
    `${PRODUCT_LEGACY_URL}/${productId}/legacy`,
  );

  if (!envelope.success) {
    throw new Error(envelope.error || "Không tải được thông tin sản phẩm.");
  }

  return envelope.data;
}
