"use client";

import Image from "next/image";
import Link from "next/link";
import { useLocale } from "next-intl";
import { useMemo, useState } from "react";
import { useProductLegacy } from "@/hooks/useProductLegacy";
import type { ProductLegacyDetailDto } from "@/lib/api/product-legacy";

interface ProductLegacyDetailProps {
  productId: number;
}

function normalizeImage(src?: string | null) {
  if (!src) return null;
  if (src.startsWith("http")) return src;
  if (src.startsWith("/")) return src;
  return `/${src}`;
}

function usePlaceholderSrc() {
  return (
    "data:image/svg+xml;utf8," +
    encodeURIComponent(
      `<svg xmlns='http://www.w3.org/2000/svg' width='320' height='240' viewBox='0 0 320 240' fill='none'><rect width='320' height='240' rx='16' fill='%23f8fafc'/><rect x='36' y='40' width='248' height='160' rx='12' fill='white' stroke='%23e2e8f0' stroke-width='2'/><path d='M84 158l54-70 50 60 34-30 18 22' stroke='%23cbd5e1' stroke-width='8' stroke-linecap='round' stroke-linejoin='round'/><circle cx='120' cy='90' r='18' fill='%23e2e8f0'/><text x='160' y='195' text-anchor='middle' fill='%2394a3b8' font-family='Arial, sans-serif' font-size='14'>No image</text></svg>`,
    )
  );
}

function InfoRow({ label, value }: { label: string; value?: string | null }) {
  if (!value) return null;
  return (
    <div className="grid grid-cols-3 text-sm text-slate-700">
      <div className="col-span-1 text-slate-500">{label}</div>
      <div className="col-span-2 font-medium text-slate-900">{value}</div>
    </div>
  );
}

export default function ProductLegacyDetail({ productId }: ProductLegacyDetailProps) {
  const locale = useLocale();
  const { data, isLoading, isError, error, refetch } = useProductLegacy(productId);
  const placeholderSrc = usePlaceholderSrc();

  const displayName = useMemo(() => {
    if (!data) return "";
    if (locale === "vi") return data.name;
    return data.nameEn?.trim() ? data.nameEn : data.name;
  }, [data, locale]);

  const shortDescription = useMemo(() => {
    if (!data) return "";
    if (locale === "vi") return data.shortContent || data.shortContentEn || "";
    return data.shortContentEn?.trim() ? data.shortContentEn : data.shortContent || "";
  }, [data, locale]);

  const htmlContent = useMemo(() => {
    if (!data) return "";
    if (locale === "vi") return data.content || data.contentEn || "";
    const en = data.contentEn && data.contentEn.trim().length > 0 ? data.contentEn : "";
    return en || data.content || "";
  }, [data, locale]);

  const images = useMemo(() => {
    if (!data) return [];
    return [data.image, data.image2, data.image3, data.image4]
      .map((src) => normalizeImage(src))
      .filter(Boolean) as string[];
  }, [data]);

  const [selectedImage, setSelectedImage] = useState<string | null>(null);

  const mainImage = selectedImage || images[0] || placeholderSrc;

  const formatPrice = (value: number) =>
    value.toLocaleString(locale === "vi" ? "vi-VN" : "en-US", { minimumFractionDigits: 0 });

  const hasDiscount =
    data &&
    data.originalPrice !== null &&
    data.originalPrice > 0 &&
    data.originalPrice > data.finalPrice;

  const discountPercent =
    hasDiscount && data
      ? Math.round(((data.originalPrice! - data.finalPrice) / data.originalPrice!) * 100)
      : 0;

  const hasStock = data ? data.quantity > 0 : false;
  const [quantity, setQuantity] = useState<number>(1);

  const handleQuantityChange = (delta: number) => {
    setQuantity((prev) => {
      if (!hasStock) return 0;
      const next = prev + delta;
      const min = 1;
      const max = data ? data.quantity : 1;
      if (next < min) return min;
      if (next > max) return max;
      return next;
    });
  };

  const handleAddToCart = () => {
    if (!data || !hasStock) return;
    console.log("add-to-cart", { productId: data.id, quantity });
  };

  const handleBuyNow = () => {
    if (!data || !hasStock) return;
    console.log("buy-now", { productId: data.id, quantity });
  };

  if (isLoading) {
    return (
      <div className="rounded-xl border border-slate-200 bg-white p-4 text-sm text-slate-600 shadow-sm">
        {locale === "vi" ? "Đang tải sản phẩm..." : "Loading product..."}
      </div>
    );
  }

  if (isError || !data) {
    return (
      <div className="rounded-xl border border-red-200 bg-red-50 p-4 text-sm text-red-700 shadow-sm">
        {error instanceof Error
          ? error.message
          : locale === "vi"
            ? "Không tải được sản phẩm."
            : "Unable to load product."}
        <button
          className="ml-3 rounded-md border border-red-200 px-3 py-1 text-xs font-medium text-red-700 hover:bg-red-100"
          onClick={() => refetch()}
        >
          {locale === "vi" ? "Thử lại" : "Retry"}
        </button>
      </div>
    );
  }

  return (
    <div className="space-y-4">
      <nav className="text-xs text-slate-500">
        <div className="flex items-center gap-1">
          <Link href={`/${locale}`} className="hover:text-primary">
            {locale === "vi" ? "Trang chủ" : "Home"}
          </Link>
          <span>/</span>
          <span className="hover:text-primary">{data.categoryName}</span>
          <span>/</span>
          <span className="text-slate-700">{displayName}</span>
        </div>
      </nav>

      <section className="mt-4 grid gap-8 lg:grid-cols-[minmax(260px,320px)_minmax(0,1fr)]">
        <div className="rounded-2xl border border-slate-200 bg-white p-3 shadow-sm">
          <div className="relative aspect-[4/3] overflow-hidden rounded-xl bg-slate-50">
            <Image
              src={mainImage}
              alt={displayName}
              fill
              sizes="(min-width: 1024px) 320px, 100vw"
              className="object-contain p-3"
              onError={(e) => {
                if ((e.target as HTMLImageElement).src !== placeholderSrc) {
                  setSelectedImage(placeholderSrc);
                }
              }}
            />
          </div>
          {images.length ? (
            <div className="mt-3 grid grid-cols-4 gap-2">
              {images.map((img) => (
                <button
                  key={img}
                  type="button"
                  onClick={() => setSelectedImage(img)}
                  className={`relative aspect-[4/3] overflow-hidden rounded-lg border ${
                    mainImage === img ? "border-primary ring-1 ring-primary" : "border-slate-200"
                  }`}
                >
                  <Image
                    src={img}
                    alt={displayName}
                    fill
                    sizes="80px"
                    className="object-contain p-1"
                    onError={(e) => {
                      (e.target as HTMLImageElement).src = placeholderSrc;
                    }}
                  />
                </button>
              ))}
            </div>
          ) : null}
        </div>

        <div className="rounded-2xl border border-slate-200 bg-white p-4 shadow-sm">
          <div className="text-xs uppercase tracking-wide text-slate-500">{data.categoryName}</div>
          <h1 className="mt-1 text-xl font-semibold text-slate-900">{displayName}</h1>
          {shortDescription ? (
            <p className="mt-2 text-sm text-slate-700">{shortDescription}</p>
          ) : null}

          <div className="mt-3 space-y-2">
            <InfoRow label={locale === "vi" ? "Mã sản phẩm" : "Code"} value={data.code} />
            <InfoRow label={locale === "vi" ? "Nhà cung cấp" : "Provider"} value={data.providerName} />
            <InfoRow label={locale === "vi" ? "Loại" : "Type"} value={data.type} />
            <InfoRow label={locale === "vi" ? "Xuất xứ" : "Origin"} value={data.origin} />
            <InfoRow label={locale === "vi" ? "Đơn vị" : "Unit"} value={data.unit} />
          </div>

          <div className="mt-4 space-y-2 rounded-xl bg-orange-50/60 p-4">
            <div className="flex items-baseline gap-2">
              <span className="text-2xl font-bold text-primary">
                {data.finalPrice > 0 ? `${formatPrice(data.finalPrice)} đ` : locale === "vi" ? "Liên hệ" : "Contact"}
              </span>
              {hasDiscount ? (
                <span className="text-sm text-slate-400 line-through">
                  {formatPrice(data.originalPrice!)} đ
                </span>
              ) : null}
              {discountPercent > 0 ? (
                <span className="rounded-full bg-red-100 px-2 py-1 text-xs font-semibold text-red-600">
                  -{discountPercent}%
                </span>
              ) : null}
            </div>
            <div className="text-sm font-medium text-slate-700">
              {hasStock
                ? `${locale === "vi" ? "Còn" : "Available"} ${data.quantity}`
                : locale === "vi"
                  ? "Hết hàng"
                  : "Out of stock"}
            </div>
          </div>

          <div className="mt-4 flex flex-wrap items-center gap-3">
            <div className="inline-flex items-center rounded-xl border border-slate-200 bg-slate-50 px-1">
              <button
                type="button"
                onClick={() => handleQuantityChange(-1)}
                disabled={!hasStock || quantity <= 1}
                className="flex h-9 w-9 items-center justify-center rounded-l-xl text-base text-slate-700 hover:bg-slate-100 disabled:cursor-not-allowed disabled:opacity-40"
              >
                −
              </button>
              <span className="w-10 text-center text-sm font-semibold text-slate-800">
                {quantity}
              </span>
              <button
                type="button"
                onClick={() => handleQuantityChange(1)}
                disabled={!hasStock || (data && quantity >= data.quantity)}
                className="flex h-9 w-9 items-center justify-center rounded-r-xl text-base text-slate-700 hover:bg-slate-100 disabled:cursor-not-allowed disabled:opacity-40"
              >
                +
              </button>
            </div>

            <button
              type="button"
              onClick={handleAddToCart}
              disabled={!hasStock}
              className="inline-flex items-center justify-center rounded-xl bg-primary px-4 py-2.5 text-sm font-semibold text-white shadow-sm transition hover:bg-primary-dark disabled:cursor-not-allowed disabled:bg-slate-300"
            >
              {locale === "vi" ? "Thêm vào giỏ" : "Add to cart"}
            </button>
            <button
              type="button"
              onClick={handleBuyNow}
              disabled={!hasStock}
              className="inline-flex items-center justify-center rounded-xl border border-primary px-4 py-2.5 text-sm font-semibold text-primary transition hover:bg-orange-50 disabled:cursor-not-allowed disabled:border-slate-300 disabled:text-slate-300"
            >
              {locale === "vi" ? "Mua ngay" : "Buy now"}
            </button>
          </div>
        </div>
      </section>

      <section className="rounded-2xl border border-slate-200 bg-white p-4 shadow-sm">
        <div className="flex flex-wrap gap-2 border-b border-slate-200 pb-2">
          <button
            type="button"
            className="rounded-lg px-3 py-1 text-sm font-semibold text-slate-800 data-[active=true]:bg-orange-50 data-[active=true]:text-primary"
            data-active="true"
          >
            {locale === "vi" ? "Thông tin sản phẩm" : "Product information"}
          </button>
          <button
            type="button"
            className="rounded-lg px-3 py-1 text-sm font-semibold text-slate-500"
            disabled
          >
            {locale === "vi" ? "Sản phẩm đề nghị" : "Suggested products"}
          </button>
          <button
            type="button"
            className="rounded-lg px-3 py-1 text-sm font-semibold text-slate-500"
            disabled
          >
            {locale === "vi" ? "Sản phẩm cùng chức năng" : "Similar products"}
          </button>
        </div>
        <div className="pt-3">
          <div
            className="prose max-w-none text-sm prose-ul:list-disc prose-li:marker:text-slate-500"
            // TODO: sanitize HTML before production (e.g. DOMPurify)
            dangerouslySetInnerHTML={{ __html: htmlContent || "" }}
          />
        </div>
      </section>
    </div>
  );
}
